import torch
import torch.nn as nn

# Simple 1D CNN for sequence classification (illustrative)
class TinyCNN(nn.Module):
    def __init__(self, vocab_size, embed_dim, num_classes):
        super().__init__()
        self.embed = nn.Embedding(vocab_size, embed_dim)
        self.conv = nn.Conv1d(embed_dim, 128, kernel_size=3, padding=1)
        self.fc = nn.Linear(128, num_classes)

    def forward(self, token_ids):
        x = self.embed(token_ids).transpose(1, 2)  # (batch, embed, seq)
        x = torch.relu(self.conv(x)).mean(dim=2)   # global average pool
        return self.fc(x)
